from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk
from config import ELASTICSEARCH_URL

INDEX_NAME = 'products'


class SearchService:
    def __init__(self):
        self.es = Elasticsearch(ELASTICSEARCH_URL)

    def index_product(self, product):
        self.es.index(index=INDEX_NAME, id=product.id, document={
            'name': product.name,
            'description': product.description,
            'category': product.category,
            'price': product.price,
        })

    def search(self, query: str, limit: int = 20) -> list[dict]:
        result = self.es.search(index=INDEX_NAME, query={
            'multi_match': {
                'query': query,
                'fields': ['name^3', 'description', 'category^2'],
                'fuzziness': 'AUTO'
            }
        }, size=limit)
        return [
            {'id': int(hit['_id']), 'score': hit['_score'], **hit['_source']}
            for hit in result['hits']['hits']
        ]

    def bulk_index(self, products):
        actions = [
            {'_index': INDEX_NAME, '_id': p.id, '_source': {
                'name': p.name, 'description': p.description,
                'category': p.category, 'price': p.price
            }}
            for p in products
        ]
        bulk(self.es, actions)
